import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.DXGyWiRo.js";const i="/assets/image%20(47).ChiHJvHg.",n="/assets/image%20(48).CW9gEsU-.",r="/assets/image%20(49).BvJ7GHLd.",l="/assets/image%20(50).CvyBLWNf.",p="/assets/image%20(51).Ceug_Wlx.",c="/assets/image%20(52).CureAHlS.",h="/assets/image%20(53).BOwB1KC-.",d="/assets/image%20(54).BZUEGznS.",m="/assets/image%20(55).C5N3LJqo.",_=JSON.parse('{"title":"How to Use Mapbox in QGIS","description":"","frontmatter":{},"headers":[],"relativePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/how-to-use-mapbox-in-qgis.md","filePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/how-to-use-mapbox-in-qgis.md"}'),u={name:"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/how-to-use-mapbox-in-qgis.md"};function g(y,e,b,f,w,x){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="how-to-use-mapbox-in-qgis" tabindex="-1">How to Use Mapbox in QGIS <a class="header-anchor" href="#how-to-use-mapbox-in-qgis" aria-label="Permalink to &quot;How to Use Mapbox in QGIS&quot;">​</a></h1><p><a href="https://www.gislounge.com/author/caitlin/" target="_blank" rel="noreferrer">Caitlin Dempsey ↗</a> | January 18, 2018 | <a href="https://www.gislounge.com/gis-101/" target="_blank" rel="noreferrer">GIS Learning ↗</a></p><p>Mapbox is a provider of a service that lets you create and serve custom online web maps. Users can customize any of the standard map styles and upload their own data to add to those maps. Low volume users can take advantage of the free plan level to access satellite and street base maps to build upon.</p><p>These map styles can also be loaded into the free and open source desktop GIS software program, QGIS. This tutorial shows how to take a map style you have created in Mapbox and load it into a QGIS session. You can also view a video version of this tutorial at the bottom of the original page.</p><p>This tutorial requires that you have an existing Mapbox account and have set up at least one map style. To get started with Mapbox, sign up for free ↗: <a href="https://www.mapbox.com/signup/?referrer=gislounge.com" target="_blank" rel="noreferrer">https://www.mapbox.com/signup/?referrer=gislounge.com</a></p><h2 id="create-a-map-style-in-mapbox" tabindex="-1">Create a Map Style in Mapbox <a class="header-anchor" href="#create-a-map-style-in-mapbox" aria-label="Permalink to &quot;Create a Map Style in Mapbox&quot;">​</a></h2><p>The first thing you will need to do in Mapbox is to create a map style in your studio ↗: <a href="https://www.mapbox.com/studio/" target="_blank" rel="noreferrer">https://www.mapbox.com/studio/</a>. To familiarize yourself with how to do that, visit the Mapbox tutorial on creating styles ↗: <a href="https://www.mapbox.com/help/create-a-custom-style/" target="_blank" rel="noreferrer">https://www.mapbox.com/help/create-a-custom-style/</a>. If you are just interested in a predesigned basemap, select one of the style templates. Type in the name for your new map style.</p><p><img src="'+i+'" alt="Map style editor"></p><p>Either customize the map style in the editor or use the default template style. From your styles page, click on the menu option for the style you want to load into QGIS.</p><p><img src="'+n+'" alt="Map styles list"></p><p>Select “Share, develop &amp; use”. Scroll down to the section that says “Use with WMTS service”. Click the toggle button to select QGIS. Then copy the URL provided in the WMTS endpoint box — you will need this URL when you open QGIS.</p><p><img src="'+r+'" alt="WMTS endpoint URL"></p><h3 id="loading-the-mapbox-style-in-qgis-using-wmts-service" tabindex="-1">Loading the Mapbox Style in QGIS Using WMTS Service <a class="header-anchor" href="#loading-the-mapbox-style-in-qgis-using-wmts-service" aria-label="Permalink to &quot;Loading the Mapbox Style in QGIS Using WMTS Service&quot;">​</a></h3><p>Open QGIS. On the far left are icons for loading different data types into QGIS. Select the globe icon to load a layer from a WMTS Server.</p><p><img src="'+l+'" alt="WMTS icon in QGIS"></p><p>Make sure the Layer option is highlighted and then select “New”. Under Connection Details type in a name for the service (e.g. Mapbox) and paste in the URL you copied from Mapbox. Hit OK.</p><p><img src="'+p+'" alt="WMTS connection dialog"></p><p>This returns you to the “Add Layer(s) from a WM(T)S Server” dialog. The “Connect” button should now be highlighted. Click “Connect” and you should see your Mapbox style name listed.</p><p><img src="'+c+'" alt="Connect to Mapbox WMTS"></p><p>Highlight the entry, give the layer a name for the QGIS Layers panel, then click Add and then Close.</p><p><img src="'+h+'" alt="Map style added to QGIS"></p><p>Your Mapbox style will now be added to the layers panel in QGIS.</p><p><img src="'+d+'" alt="Mapbox style in QGIS layers"></p><p>Notes:</p><ul><li>The style loads as a flat (raster) layer: you can pan and zoom, but you cannot toggle individual Mapbox style layers on/off from QGIS as you can in Mapbox Studio. Style behaviors such as scale-dependent rendering and labeling are preserved; zooming will show style changes.</li><li>You can load other GIS data on top of the Mapbox style and change the projection. In the example shown, a shapefile of ocean debris landings was added and reprojected from Mapbox’s default Web Mercator to a Pacific-centric WGS 1984 PDC Mercator projection.</li></ul><p><img src="'+m+'" alt="Reprojected data over Mapbox style"></p>',26)])])}const M=t(u,[["render",g]]);export{_ as __pageData,M as default};
